<script setup lang="ts">
import{onMounted,ref}from'vue';import{useRoute,useRouter}from'vue-router';import{ElMessage,ElMessageBox}from'element-plus';import{api}from'../api/client';import type{Book,BookFile}from'../types/book';import{readingStatusLabel}from'../utils/book';const route=useRoute(),router=useRouter();const book=ref<Book>(),loading=ref(true),uploading=ref(false);async function load(){loading.value=true;try{book.value=(await api.get<Book>(`/books/${route.params.id}`)).data}finally{loading.value=false}}async function remove(){await ElMessageBox.confirm('将这本书移入回收站？','确认删除',{type:'warning'});await api.delete(`/books/${route.params.id}`);await router.push('/')}function size(n:number){return(n/1024/1024).toFixed(1)+' MB'}async function addFile(e:Event){const file=(e.target as HTMLInputElement).files?.[0];if(!file)return;uploading.value=true;const data=new FormData();data.append('file',file);try{await api.post(`/books/${route.params.id}/files`,data);ElMessage.success('文件已添加');await load()}catch(err:any){ElMessage.error(err.response?.data?.error||'添加失败')}finally{uploading.value=false;(e.target as HTMLInputElement).value=''}}async function deleteFile(file:BookFile){await ElMessageBox.confirm(`删除文件“${file.original_name}”？文件将移入回收站。`,'确认删除',{type:'warning'});await api.delete(`/books/${route.params.id}/files/${file.id}`);ElMessage.success('文件已删除');await load()}onMounted(load)
</script>
<template><section v-loading="loading"><template v-if="book"><el-page-header @back="$router.push('/')" title="返回书库"><template #extra><el-button type="primary" @click="$router.push(`/books/${book.id}/edit`)">编辑</el-button></template></el-page-header><div class="detail"><img v-if="book.cover_path" :src="`/api/v1/books/${book.id}/cover`"/><div><h1>{{book.title}}</h1><h2>{{book.subtitle}}</h2><p>{{book.authors.map(a=>a.name).join('、')||'未知作者'}}</p><p><el-tag v-for="tag in book.tags" :key="tag.id">{{tag.name}}</el-tag></p><p>{{book.description||'暂无简介'}}</p><el-descriptions border :column="2"><el-descriptions-item label="语言">{{book.language||'-'}}</el-descriptions-item><el-descriptions-item label="出版社">{{book.publisher||'-'}}</el-descriptions-item><el-descriptions-item label="ISBN">{{book.isbn||'-'}}</el-descriptions-item><el-descriptions-item label="状态">{{readingStatusLabel(book.reading_status)}}</el-descriptions-item></el-descriptions><div class="files-head"><h3>文件</h3><label class="upload"><input type="file" accept=".epub,.pdf,.mobi,.azw3,.txt" :disabled="uploading" @change="addFile"/><el-button type="primary" :loading="uploading">添加文件</el-button></label></div><el-table :data="book.files"><el-table-column label="文件名" min-width="220"><template #default="s"><span class="file-name" :title="s.row.original_name">{{s.row.original_name}}</span></template></el-table-column><el-table-column prop="format" label="格式"/><el-table-column label="大小"><template #default="s">{{size(s.row.file_size)}}</template></el-table-column><el-table-column width="140" label="操作"><template #default="s"><el-link :href="`/api/v1/books/${book.id}/files/${s.row.id}/download`">下载</el-link><el-button link type="danger" @click="deleteFile(s.row)">删除</el-button></template></el-table-column></el-table><el-button class="delete" type="danger" plain @click="remove">移入回收站</el-button></div></div></template></section></template>
<style scoped>.detail{display:grid;grid-template-columns:220px minmax(0,1fr);gap:2rem;margin-top:2rem}.detail>img{width:220px;max-height:330px;object-fit:cover}h2{font-weight:400;color:#909399}.el-tag{margin-right:.4rem}.files-head{display:flex;align-items:center;justify-content:space-between;margin-top:1rem}.file-name{display:block;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.upload{position:relative}.upload input{position:absolute;inset:0;opacity:0;cursor:pointer}.delete{margin-top:2rem}@media(max-width:650px){.detail{grid-template-columns:1fr}.detail>img{margin:auto}}</style>
